INSERT INTO recruitment_forms (coach_id, title, description, questions, status) VALUES ((SELECT id FROM coaches WHERE role = 'super_admin' LIMIT 1), 'Recrutement Setter-Closer Fitzone Evolution', 'Merci de remplir ce formulaire avec soin. Tes reponses nous aideront a evaluer ta candidature.', '[{"id":"q1","type":"radio","label":"Es-tu disponible IMMEDIATEMENT pour demarrer cette mission ?","required":true,"options":["Oui, dans les 7 jours","Oui, mais dans 2 a 4 semaines","Non, je cherche pour dans + de 1 mois"]},{"id":"q2","type":"radio","label":"Peux-tu garantir une disponibilite TOUS LES JOURS entre 12h-14h ET 17h-19h (heure francaise) ?","required":true,"options":["Oui, sans probleme","Oui, mais avec quelques exceptions (precise lesquelles dans la question suivante)","Non, je ne peux pas m engager sur ces creneaux"]},{"id":"q2b","type":"short","label":"Si exceptions de disponibilite, precise lesquelles :","required":false,"options":[]},{"id":"q3","type":"radio","label":"Combien d heures par semaine peux-tu consacrer a cette mission ?","required":true,"options":["10-20h/semaine (mi-temps)","20-35h/semaine (temps partiel intensif)","35h+/semaine (temps plein)"]},{"id":"q4","type":"radio","label":"As-tu un autre job/mission en parallele actuellement ?","required":true,"options":["Oui","Non, je suis 100% dispo"]},{"id":"q4b","type":"short","label":"Si oui, precise ton autre job/mission :","required":false,"options":[]},{"id":"q5","type":"radio","label":"As-tu deja fait du SETTING (qualification de leads + prise de RDV closing) ?","required":true,"options":["Oui, regulierement (+ de 6 mois d experience)","Oui, ponctuellement (- de 6 mois)","Non, jamais"]},{"id":"q6","type":"long","label":"Si OUI : Pour quelle(s) entreprise(s) / coach(s) / marque(s) as-tu travaille en tant que Setter ? (Donne 2-3 noms)","required":false,"options":[]},{"id":"q7","type":"long","label":"Quel etait le produit/service que tu settais, et quel etait son prix moyen ?","required":false,"options":[]},{"id":"q8","type":"radio","label":"Quel etait ton taux de SHOW-UP moyen (% de RDV poses qui se presentaient au call de closing) ?","required":false,"options":["Je ne sais pas / je n ai jamais mesure","Moins de 50%","Entre 50% et 70%","Plus de 70%"]},{"id":"q9","type":"radio","label":"As-tu deja CLOSE des ventes (= transformation prospect -> client payant) ?","required":true,"options":["Oui, regulierement (+ de 6 mois d experience)","Oui, ponctuellement (- de 6 mois)","Non, jamais"]},{"id":"q10","type":"radio","label":"Si OUI : Quel est le ticket moyen des offres que tu as deja vendues ?","required":false,"options":["Moins de 500 euros","Entre 500 et 1500 euros","Entre 1500 et 3000 euros","Plus de 3000 euros"]},{"id":"q11","type":"radio","label":"Quel etait ton taux de CLOSING moyen (% de calls qui se transformaient en vente) ?","required":false,"options":["Je ne sais pas / je n ai jamais mesure","Moins de 20%","Entre 20% et 40%","Plus de 40%"]},{"id":"q12","type":"radio","label":"As-tu deja vendu des programmes de COACHING ou d ACCOMPAGNEMENT (sante, business, dev perso, fitness) ?","required":true,"options":["Oui, c est mon domaine principal","Oui, mais dans un autre secteur (precise dans la question suivante)","Non, jamais"]},{"id":"q12b","type":"short","label":"Si autre secteur, precise lequel :","required":false,"options":[]},{"id":"q13","type":"long","label":"Un lead remplit ton formulaire a 13h45. Tu le rappelles a 13h50. Il ne repond pas. Que fais-tu dans les 2 heures qui suivent ? (Decris ton process exact, etape par etape)","required":true,"options":[]},{"id":"q14","type":"long","label":"Tu es en call de closing avec un prospect interesse par ton offre a 2200 euros. Il te dit : C est cher, je vais reflechir. Que lui reponds-tu MOT POUR MOT ?","required":true,"options":[]},{"id":"q15","type":"long","label":"Pourquoi veux-tu travailler comme Setter-Closer pour un coaching fitness haut de gamme ? (Sois honnete)","required":true,"options":[]},{"id":"q16","type":"long","label":"Quelle est ta plus grosse fierte en vente ? (Un resultat concret, chiffre si possible)","required":true,"options":[]}]'::jsonb, 'active');
